void Font_Load(void) {
    /* Load 128 main font tiles at slots 128–255 */
    for (int i = 0; i < 128; i++)
        Display_LoadTile((uint8_t)(FONT_TILE_BASE + i), gFontTiles[i]);
    /* Load 6 box-drawing tiles at slots 120–125, blank at 126 */
    for (int i = 0; i < 7; i++)
        Display_LoadTile((uint8_t)(BOX_TILE_BASE + i), gBoxTiles[i]);
}

void Font_LoadHudTiles(void) {
    /* Load HP bar + HUD border tiles ($62–$78) at slots HUD_TILE_BASE..HUD_TILE_BASE+22.
     * Matches LoadHudAndHpBarAndStatusTilePatterns in the original game. */
    for (int i = 0; i < 23; i++)
        Display_LoadTile((uint8_t)(HUD_TILE_BASE + i), gHudTiles[i]);
}

